$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_83112255bb4233cad4276eab160483e8'] = 'Zapína alebo vypína čistič. Keď je vypnutý, cron URL ani tlačidlo ručného spustenia nebudú mazať staré štatistiky. Použite tento prepínač, keď chcete modul ponechať nainštalovaný, ale dočasne zastaviť všetky čistiace úlohy.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_896e1fd6ab19d8bbd2f58f989fbaac76'] = 'Počet dní uchovania štatistík pripojení';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_b878a67f82524d412dae79ad597ff402'] = 'Riadky staršie ako táto hodnota budú odstránené z tabuliek connections, connections_source a connections_page.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_5ee406d769ac3887713d3308a0d01601'] = 'Zadajte počet dní, počas ktorých sa majú uchovať surové návštevnostné štatistiky PrestaShopu. Príklad: 60 znamená, že modul ponechá posledných 60 dní a staršie záznamy z tabuliek ps_connections, ps_connections_source a ps_connections_page odstráni. Nenastavujte hodnotu 1, ak si nie ste istý, že nepotrebujete nedávne návštevnostné štatistiky.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_1300769d8d72fc8218b40772f1c25efc'] = 'Veľkosť dávky';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_631c4c75cb36e0fcee3da42ef67e730e'] = 'Maximálny počet pripojení spracovaných v jednej dávke.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_acbc6e359c79ace4ef9b5398148c13e2'] = 'Zadajte, koľko hlavných záznamov pripojení sa môže spracovať v jednej internej dávke. Menšie hodnoty sú bezpečnejšie na slabom hostingu, ale vyžadujú viac spustení cronu. Väčšie hodnoty čistia rýchlejšie, ale môžu dlhšie držať databázové zámky. Odporúčaná počiatočná hodnota: 1000 až 5000; zvyšujte ju až po otestovaní času behu.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_2806977593fb4c23003cc11306b135d1'] = 'Maximálny počet dávok na jedno spustenie';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_d31a094a19379b58b63b51ef0f9d9362'] = 'Obmedzuje množstvo práce, ktorú môže vykonať jedno spustenie cronu.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_e221a5a91ea62a43adc5bb15614eb578'] = 'Zadajte, koľko dávok môže prebehnúť počas jedného spustenia cronu. Celkový možný počet odstránených hlavných záznamov pripojení na jedno spustenie je približne Veľkosť dávky krát Maximálny počet dávok. Príklad: 5000 a 10 znamená približne do 50000 hlavných záznamov pripojení za jedno spustenie cronu. Znížte túto hodnotu, ak sa obchod počas čistenia spomaľuje.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_a1a47524ffa9c839887703df1fbe70a3'] = 'Vyčistiť ps_layered_filter_block';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_924684322fe68e56ef9205e7f480f598'] = 'Vyčistí cache bloku filtrovaného/fasetového vyhľadávania pomocou TRUNCATE TABLE. Tabuľka bude v MySQL/MariaDB znovu vytvorená ako prázdna.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_92a6452eb793565a92aa28e5f9a3f2e5'] = 'Zapnite iba vtedy, keď tabuľka ps_layered_filter_block príliš narastá alebo obsahuje neaktuálnu cache fasetového vyhľadávania. Neodstraňuje produkty, kategórie ani index vrstvených cien. Po vyčistení môže PrestaShop alebo modul fasetového vyhľadávania túto cache podľa potreby znovu vytvoriť.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_bf45506cce2494894a9df6ff4bdf83ae'] = 'Agregovať štatistiky zdrojov návštevnosti pred odstránením';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_d7e1a0c7e7973ebcde37aa659525105d'] = 'Ukladá denné súhrnné štatistiky zdrojov návštevnosti pred odstránením surových riadkov.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_ae729759e10d7a626a8622321932a1f4'] = 'Keď je zapnuté, modul pred odstránením surových štatistík PrestaShopu uloží malý denný súhrn. Uchováva počty ako návštevy, zobrazenia stránok, zdrojovú doménu a UTM hodnoty. Neukladá IP adresy, celé referrer URL ani user-agent reťazce. Vypnite, ak chcete iba mazať a nepotrebujete historické súhrny zdrojov.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_ce2b282d224153cccd645f28504ab4e2'] = 'Počet dní uchovania agregovaných štatistík';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_c3b4d14f7bff29c221039e891918f2dd'] = 'Ako dlho sa má uchovávať malá denná súhrnná tabuľka.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_a97a6a6ab09f48206a543fdc7321bb60'] = 'Zadajte, koľko dní majú súhrny zdrojov návštevnosti zostať v tabuľke modulu. Príklad: 730 uchová približne dva roky denných súhrnov zdrojov. Toto nastavenie ovplyvňuje iba tabuľku modulu ps_jooim_dbcleaner_traffic_daily, nie pôvodné štatistické tabuľky PrestaShopu.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_4d4c70d739ad72835a8b62a81e07c611'] = 'Časový limit zastaraného zámku v sekundách';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_ef4f59605eb7e54ec7df26e3755b7edf'] = 'Ochrana proti súbežnému spusteniu dvoch čistiacich procesov.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_2c1824ea38ec688698a26f01a46e6b16'] = 'Zadajte počet sekúnd, po ktorých sa nedokončený zámok čistenia považuje za opustený. Chráni databázu pred tým, aby naraz bežali dve spustenia cronu. Odporúčaná hodnota: 7200. Znižujte ju iba vtedy, ak máte istotu, že cron vždy skončí rýchlo.';
